def guard(features: dict, prediction: str) -> str:
    """Skip trades against OBV volume flow direction."""
    obv_slope = features.get("obv_slope", 0)

    # Skip longs when OBV slope is negative (smart money distributing)
    if prediction == "long" and obv_slope < 0:
        return "skip"
    # Skip shorts when OBV slope is positive (smart money accumulating)
    if prediction == "short" and obv_slope > 0:
        return "skip"
    return prediction
